import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

import axios from "axios";
import Api from "../api/Api";


function AssignLocation() {
  const [supervisors, setSupervisors] = useState([]);
  const [selectedSupervisor, setSelectedSupervisor] =
    useState("");
  const [selectedZone, setSelectedZone] =
useState("");

  const [menuOpen, setMenuOpen] = useState(false);


  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get(
        Api.get_All_User
      );

      const onlySupervisors =
        res.data.filter(
          (u) => u.role === "supervisor"
        );

      setSupervisors(onlySupervisors);

    } catch (err) {
      console.log(err);
    }
  };

  const assignZone = async () => {
    try {
      if (!selectedSupervisor) {
        return alert("Select Supervisor");
      }

      if (!selectedZone) {
        return alert("Select Zone");
      }

      const res = await axios.put(
        Api.assign_Zone,
        {
          supervisorId:
            selectedSupervisor,
          zone: selectedZone,
        }
      );

      console.log(res.data);

      alert(
        `Zone Assigned Successfully\nLocations Assigned: ${res.data.locationsCount}`
      );

      setSelectedSupervisor("");
      setSelectedZone("");

    } catch (err) {

      console.log(
        err.response?.data || err
      );

      alert("Assignment Failed");
    }
  };

  return (
    
    <div className="min-h-screen bg-green-50 ">
  {/* Header */}
      {/* <div className="mb-8 bg-[#4CBB17]/40 px-8">
        <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
          <img
            src="garbageVehicle.jpeg"
            alt="CleanTrack Logo"
            className="w-16 h-16 object-contain"
          />

          CleanTrack
        </h1>
        <p className="text-gray-900  p-2  ">
          Smart Waste Management Control Center
        </p>
      </div> */}
<div className="mb-8 bg-[#4CBB17]/40 px-4 md:px-6 py-3">
  <div className="flex items-center justify-between">

    {/* Logo */}
    <div>
      <h1 className="flex items-center gap-2 md:gap-3 text-3xl md:text-5xl font-extrabold text-green-900">
        <img
          src="/garbageVehicle.jpeg"
          alt=""
          className="w-10 h-10 md:w-16 md:h-16 object-contain"
        />
        CleanTrack
      </h1>

      <p className="text-gray-900 text-xs md:text-base mt-1">
        Smart Waste Management Control Center
      </p>
    </div>

    {/* Mobile Menu Button */}
    <button
      className="md:hidden text-3xl font-bold"
      onClick={() => setMenuOpen(!menuOpen)}
    >
      ☰
    </button>

    {/* Desktop Menu */}
    <div className="hidden md:flex items-center gap-8 text-lg font-semibold">

      <Link
        to="/create-account"
        className="text-green-900 hover:scale-105 transition"
      >
        Create User
      </Link>

      <button
        onClick={() => {
          setShowRequests(!showRequests);
          fetchRequests();
        }}
        className="text-green-900 hover:scale-105 transition"
      >
        View Requests
      </button>

      <Link
        to="/create-location"
        className="text-green-900 hover:scale-105 transition"
      >
        Create Locations
      </Link>

      <Link
        to="/assign-location"
        className="text-green-900 hover:scale-105 transition"
      >
        Assign Location
      </Link>

      <Link
        to="/days-report"
        className="text-green-900 hover:scale-105 transition"
      >
        Days Report
      </Link>

    </div>
  </div>

  {/* Mobile Dropdown Menu */}
  {menuOpen && (
    <div className="md:hidden mt-4 flex flex-col gap-4 text-green-900 font-semibold">

      <Link
        to="/create-account"
        onClick={() => setMenuOpen(false)}
      >
        Create User
      </Link>

      <button
        className="text-left"
        onClick={() => {
          setShowRequests(!showRequests);
          fetchRequests();
          setMenuOpen(false);
        }}
      >
        View Requests
      </button>

      <Link
        to="/create-location"
        onClick={() => setMenuOpen(false)}
      >
        Create Locations
      </Link>

      <Link
        to="/assign-location"
        onClick={() => setMenuOpen(false)}
      >
        Assign Location
      </Link>

      <Link
        to="/days-report"
        onClick={() => setMenuOpen(false)}
      >
        Days Report
      </Link>

    </div>
  )}
</div>
      
      <div className="max-w-2xl mx-auto bg-white rounded-2xl shadow-sm p-6">

        <h2 className="text-2xl font-bold text-green-900 mb-5">
          Assign Zone To Supervisor
        </h2>

        {/* Supervisor Dropdown */}

        <select
          className="border p-3 rounded w-full mb-4"
          value={selectedSupervisor}
          onChange={(e) =>
            setSelectedSupervisor(
              e.target.value
            )
          }
        >
          <option value="">
            Select Supervisor
          </option>

          {supervisors.map((sup) => (
            <option
              key={sup._id}
              value={sup._id}
            >
              {sup.name}
            </option>
          ))}
        </select>

        {/* Zone Dropdown */}

        <select
          className="border p-3 rounded w-full mb-4"
          value={selectedZone}
          onChange={(e) =>
            setSelectedZone(
              e.target.value
            )
          }
        >
          <option value="">
            Select Zone
          </option>

          <option value="Hostel Zone 1">
            Hostel Zone 1
          </option>

          <option value="Hostel Zone 2">
            Hostel Zone 2
          </option>

          <option value="Academic Zone">
            Academic Zone
          </option>

          <option value="Colony Zone">
            Colony Zone
          </option>
        </select>

        <button
          onClick={assignZone}
          className="bg-green-800 hover:bg-green-900 text-white px-5 py-3 rounded w-full"
        >
          Assign Zone
        </button>

      </div>

    </div>
  );
}

export default AssignLocation;
